import{_ as i,o as a,c as t,ae as n}from"./chunks/framework.CyZiF_rV.js";const m=JSON.parse('{"title":"KSeF 2.0 - Guide for Integrators","description":"","frontmatter":{},"headers":[],"relativePath":"en/index.md","filePath":"en/index.md"}'),r={name:"en/index.md"};function o(l,e,s,c,h,d){return a(),t("div",null,[...e[0]||(e[0]=[n('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/README.md" target="_blank" rel="noreferrer">README.md</a></p></blockquote><h1 id="ksef-2-0-guide-for-integrators" tabindex="-1"><strong>KSeF 2.0 - Guide for Integrators</strong> <a class="header-anchor" href="#ksef-2-0-guide-for-integrators" aria-label="Permalink to &quot;**KSeF 2.0 \\- Guide for Integrators**&quot;">​</a></h1><p>22.12.2025</p><p>This document is a compendium of knowledge for developers, analysts, and system integrators implementing integration with the National e-Invoice System (KSeF) version 2.0. The guide focuses on the technical and practical aspects of communicating with the KSeF system API.</p><h2 id="introduction-to-ksef-2-0" tabindex="-1">Introduction to KSeF 2.0 <a class="header-anchor" href="#introduction-to-ksef-2-0" aria-label="Permalink to &quot;Introduction to KSeF 2.0&quot;">​</a></h2><p>The National e-Invoice System (KSeF) is a central IT system for issuing and retrieving structured invoices in electronic form.</p><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><p>The guide is divided into thematic sections corresponding to key functions and integration areas in the KSeF API:</p><ul><li><a href="./przeglad-kluczowych-zmian-ksef-api-2-0.html">Overview of Key Changes in KSeF 2.0</a></li><li><a href="./api-changelog.html">Changelog</a></li><li>Authentication <ul><li><a href="./uwierzytelnianie.html">Obtaining Access</a></li><li><a href="./auth/sesje.html">Session Management</a></li></ul></li><li><a href="./uprawnienia.html">Permissions</a></li><li><a href="./certyfikaty-KSeF.html">KSeF Certificates</a></li><li>Offline Modes <ul><li><a href="./tryby-offline.html">Offline Modes</a></li><li><a href="./offline/korekta-techniczna.html">Technical Correction</a></li></ul></li><li><a href="./kody-qr.html">QR Codes</a></li><li><a href="./sesja-interaktywna.html">Interactive Session</a></li><li><a href="./sesja-wsadowa.html">Batch Session</a></li><li>Downloading Invoices <ul><li><a href="./pobieranie-faktur/pobieranie-faktur.html">Downloading Invoices</a></li><li><a href="./pobieranie-faktur/przyrostowe-pobieranie-faktur.html">Incremental Invoice Download</a></li></ul></li><li><a href="./tokeny-ksef.html">KSeF Token Management</a></li><li><a href="./limity/limity.html">Limits</a></li><li><a href="./dane-testowe-scenariusze.html">Test Data</a></li></ul><p>For each area, the following is provided:</p><ul><li>detailed description of operation,</li><li>example calls in C# and Java,</li><li>links to the <a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">OpenAPI</a> specification and reference library code.</li></ul><p>The code examples presented in the guide were prepared based on the official open source libraries:</p><ul><li><a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">ksef-client-csharp</a> – C# library</li><li><a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">ksef-client-java</a> – Java library</li></ul><p>Both libraries are maintained and developed by the Ministry of Finance teams and are publicly available under open source terms. They provide full support for KSeF API 2.0 functionality, including handling of all endpoints, data models, and example call scenarios. Using these libraries significantly simplifies the integration process and minimizes the risk of misinterpreting API contracts.</p><h2 id="system-environments" tabindex="-1">System Environments <a class="header-anchor" href="#system-environments" aria-label="Permalink to &quot;System Environments&quot;">​</a></h2><p>A list of KSeF API 2.0 environments is described in the <a href="./srodowiska.html">KSeF API 2.0 Environments</a> document.</p>',16)])])}const p=i(r,[["render",o]]);export{m as __pageData,p as default};
